INSERT INTO `v1_59595eb7545b5da9733452bae640873dce280709ff939d90ae9be81fd956b900` VALUES (1, 0, 10, "アオイさんですよね～っ！？\nグランドリームパークへようこそっ♪\n本日はおひとりさまですますか？", 0, 5146066, 11, 130911, 0, 1, 66032);
